// Generate unique session ID and process payment request
const sessionId = 'sess_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

const body = $input.first().json.body || {};

const intent = (body.intent || '').toLowerCase();
const plan = body.plan || body.formPayload?.plan || null;
const paymentType = body.paymentType || body.formPayload?.paymentType || 'monthly';
const buyer = body.buyer || body.formPayload?.buyer || body.formPayload?.titular || {};
const family = body.family || body.formPayload?.family || [];
const timestamp = body.timestamp || new Date().toISOString();

const buyerName = buyer.name || '';
const buyerLastName = buyer.lastName || '';
const buyerEmail = buyer.email || '';
const buyerPhone = buyer.phone || '';

return [{
  json: {
    sessionId,
    intent,
    plan,
    paymentType,
    buyer: {
      name: buyerName,
      lastName: buyerLastName,
      email: buyerEmail,
      phone: buyerPhone
    },
    family: family,
    timestamp,
    email: buyerEmail,
    customerName: buyerName + ' ' + buyerLastName
  }
}];

// Calculate amount based on plan and payment type
const plan = $('Process Payment Request').item.json.plan;
const paymentType = $('Process Payment Request').item.json.paymentType;

const amounts = {
  'esencial-zulia': { monthly: 947, annual: 9470 },
  'vanguardia-zulia': { monthly: 1470, annual: 14700 },
  'esencial-selecto': { monthly: 947, annual: 20200 },
  'vanguardia-selecto': { monthly: 1470, annual: 12970 }
};

const planAmounts = amounts[plan] || amounts['esencial-zulia'];
const amount = paymentType === 'annual' ? planAmounts.annual : planAmounts.monthly;

return [{
  json: {
    ...$('Process Payment Request').item.json,
    amount: amount
  }
}];

// Parse Stripe webhook event
const body = $input.first().json.body || {};

const eventType = body.type || '';
const dataObj = (body.data && body.data.object) ? body.data.object : {};

let chargeData = {};
if (dataObj.charges && dataObj.charges.data && dataObj.charges.data.length > 0) {
  chargeData = dataObj.charges.data[0];
} else if (dataObj.latest_charge) {
  chargeData = { id: dataObj.latest_charge };
}

const meta = dataObj.metadata || {};

return [{
  json: {
    eventType,
    eventId: body.id || '',
    paymentIntentId: dataObj.id || '',
    status: dataObj.status || '',
    amount: dataObj.amount || 0,
    amountReceived: dataObj.amount_received || 0,
    currency: dataObj.currency || 'usd',
    sessionId: meta.sessionId || '',
    plan: meta.plan || '',
    paymentType: meta.paymentType || '',
    customerEmail: meta.customerEmail || '',
    customerName: meta.customerName || '',
    succeeded: dataObj.status === 'succeeded',
    created: dataObj.created || 0,
    chargeId: chargeData.id || '',
    chargeStatus: chargeData.status || '',
    receiptUrl: chargeData.receipt_url || '',
    failureMessage: dataObj.last_payment_error?.message || '',
    failureCode: dataObj.last_payment_error?.code || ''
  }
}];

// Find client by email or prepare for new client
const inputData = $('Parse Stripe Event').item.json;
const clients = $input.all();

const customerEmail = inputData.customerEmail;

const existingClient = clients.find(client => {
  const contacts = client.json.contacts || [];
  return contacts.some(contact => contact.email === customerEmail);
});

// Generate temporary password for new client
const tempPassword = generateTempPassword();

if (existingClient) {
  return [{
    json: {
      ...inputData,
      clientId: existingClient.json.id,
      isNewClient: false
    }
  }];
}

return [{
  json: {
    ...inputData,
    clientId: null,
    isNewClient: true,
    tempPassword: tempPassword
  }
}];

function generateTempPassword() {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789';
  let password = '';
  for (let i = 0; i < 12; i++) {
    password += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return password;
}

// Extract the created client ID
const input = $('Create IN Client').item.json;
return [{
  json: {
    ...$('Find or Create Client').item.json,
    clientId: input.id,
    clientCreated: true
  }
}];

// Use existing client ID
const input = $('Find or Create Client').item.json;
return [{
  json: {
    ...input,
    clientCreated: false
  }
}];

// Prepare email content based on client status
const input = $('Merge Client Paths').item.json;

let emailSubject, emailBody;

if (input.isNewClient && input.tempPassword) {
  emailSubject = 'Bienvenido a LEGADO! Tu cuenta ha sido creada';
  emailBody = 'Felicidades! Tu pago ha sido procesado exitosamente.\n\n' +
    'DETALLES DE TU PLAN:\n' +
    '- Plan: ' + input.plan + '\n' +
    '- Tipo: ' + input.paymentType + '\n' +
    '- Monto: $' + (input.amount / 100).toFixed(2) + ' USD\n' +
    '- ID de Transaccion: ' + input.paymentIntentId + '\n\n' +
    'TUS CREDENCIALES DE ACCESO AL PORTAL:\n\n' +
    'URL: https://invoicing.legadoholding.com/client/login\n' +
    'Email: ' + input.customerEmail + '\n' +
    'Contrasena temporal: ' + input.tempPassword + '\n\n' +
    'Por seguridad, te recomendamos cambiar tu contrasena despues de iniciar sesion.\n\n' +
    'El equipo de LEGADO';
} else {
  emailSubject = 'Confirmacion de pago - LEGADO';
  emailBody = 'Tu pago ha sido procesado exitosamente.\n\n' +
    'DETALLES:\n' +
    '- Plan: ' + input.plan + '\n' +
    '- Tipo: ' + input.paymentType + '\n' +
    '- Monto: $' + (input.amount / 100).toFixed(2) + ' USD\n\n' +
    'ACCEDE A TU PORTAL:\n' +
    'URL: https://invoicing.legadoholding.com/client/login\n' +
    'Email: ' + input.customerEmail + '\n\n' +
    'El equipo de LEGADO';
}

return [{
  json: {
    ...input,
    emailSubject,
    emailBody,
    invoiceId: $('Create Invoice').item.json.id,
    invoiceNumber: $('Create Invoice').item.json.invoice_number
  }
}];
